            HorizontalDivider(color = colors.divider)
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 8.dp),
                contentAlignment = Alignment.CenterEnd
            ) {
                Button(
                    onClick = { viewModel.saveDraft() },
                    enabled = saveEnabled,
                    shape = RoundedCornerShape(AppShapes.pillRadius),
