                ) {
                    Text(
                        text = if (uiState.isSaving) {
                            stringResource(R.string.saving_draft)
                        } else {
                            stringResource(R.string.save_draft)
                        },
                        color = Color.White
                    )
                }
            }
        }
    }
}

