1	package pub.hackers.android.ui.screens.timeline
2	
3	import androidx.lifecycle.ViewModel
4	import androidx.lifecycle.viewModelScope
5	import dagger.hilt.android.lifecycle.HiltViewModel
6	import kotlinx.coroutines.flow.MutableStateFlow
7	import kotlinx.coroutines.flow.StateFlow
8	import kotlinx.coroutines.flow.asStateFlow
9	import kotlinx.coroutines.flow.update
10	import kotlinx.coroutines.launch
11	import pub.hackers.android.data.local.PreferencesManager
12	import pub.hackers.android.data.repository.HackersPubRepository
13	import pub.hackers.android.domain.model.Post
14	import pub.hackers.android.domain.model.ReactionGroup
15	import java.time.Instant
16	import javax.inject.Inject
17	
18	data class TimelineUiState(
19	    val posts: List<Post> = emptyList(),
20	    val isLoading: Boolean = false,
21	    val isRefreshing: Boolean = false,
22	    val isLoadingMore: Boolean = false,
23	    val hasNextPage: Boolean = false,
24	    val endCursor: String? = null,
25	    val error: String? = null,
26	    val reactionPickerPostId: String? = null
27	)
28	
29	@HiltViewModel
30	class TimelineViewModel @Inject constructor(
31	    private val repository: HackersPubRepository,
32	    val preferencesManager: PreferencesManager
33	) : ViewModel() {
34	
35	    private val _uiState = MutableStateFlow(TimelineUiState())
36	    val uiState: StateFlow<TimelineUiState> = _uiState.asStateFlow()
37	
38	    private var lastLoadTime: Instant? = null
39	    private val staleThresholdSeconds = 60L
40	
41	    init {
42	        loadTimeline()
43	    }
44	
45	    fun refreshIfStale() {
46	        val last = lastLoadTime ?: return
47	        if (Instant.now().epochSecond - last.epochSecond > staleThresholdSeconds) {
48	            refresh()
49	        }
50	    }
51	
52	    private fun loadTimeline() {
53	        viewModelScope.launch {
54	            _uiState.update { it.copy(isLoading = true, error = null) }
55	
56	            repository.getPersonalTimeline(refresh = true)
57	                .onSuccess { result ->
58	                    lastLoadTime = Instant.now()
59	                    _uiState.update {
60	                        it.copy(
61	                            posts = result.posts,
62	                            hasNextPage = result.hasNextPage,
63	                            endCursor = result.endCursor,
64	                            isLoading = false
65	                        )
66	                    }
67	                }
68	                .onFailure { error ->
69	                    _uiState.update {
70	                        it.copy(
71	                            error = error.message,
72	                            isLoading = false
73	                        )
74	                    }
75	                }
76	        }
77	    }
78	
79	    fun refresh() {
80	        viewModelScope.launch {
81	            _uiState.update { it.copy(isRefreshing = true, error = null) }
82	
83	            repository.getPersonalTimeline(refresh = true)
84	                .onSuccess { result ->
85	                    lastLoadTime = Instant.now()
86	                    _uiState.update {
87	                        it.copy(
88	                            posts = result.posts,
89	                            hasNextPage = result.hasNextPage,
90	                            endCursor = result.endCursor,
91	                            isRefreshing = false
92	                        )
93	                    }
94	                }
95	                .onFailure { error ->
96	                    _uiState.update {
97	                        it.copy(
98	                            error = error.message,
99	                            isRefreshing = false
100	                        )
101	                    }
102	                }
103	        }
104	    }
105	
106	    fun loadMore() {
107	        val currentState = _uiState.value
108	        if (!currentState.hasNextPage || currentState.isLoadingMore) return
109	
110	        viewModelScope.launch {
111	            _uiState.update { it.copy(isLoadingMore = true) }
112	
113	            repository.getPersonalTimeline(after = currentState.endCursor)
114	                .onSuccess { result ->
115	                    _uiState.update {
116	                        it.copy(
117	                            posts = (it.posts + result.posts).distinctBy { p -> p.id },
118	                            hasNextPage = result.hasNextPage,
119	                            endCursor = result.endCursor,
120	                            isLoadingMore = false
121	                        )
122	                    }
123	                }
124	                .onFailure {
125	                    _uiState.update { it.copy(isLoadingMore = false) }
126	                }
127	        }
128	    }
129	
130	    fun sharePost(postId: String) {
131	        // Optimistic update
132	        _uiState.update { state ->
133	            state.copy(
134	                posts = state.posts.map { post ->
135	                    if (post.id == postId) {
136	                        post.copy(
137	                            viewerHasShared = true,
138	                            engagementStats = post.engagementStats.copy(
139	                                shares = post.engagementStats.shares + 1
140	                            )
141	                        )
142	                    } else post
143	                }
144	            )
145	        }
146	        viewModelScope.launch {
147	            repository.sharePost(postId)
148	                .onFailure {
149	                    // Revert on failure
150	                    _uiState.update { state ->
151	                        state.copy(
152	                            posts = state.posts.map { post ->
153	                                if (post.id == postId) {
154	                                    post.copy(
155	                                        viewerHasShared = false,
156	                                        engagementStats = post.engagementStats.copy(
157	                                            shares = maxOf(0, post.engagementStats.shares - 1)
158	                                        )
159	                                    )
160	                                } else post
161	                            }
162	                        )
163	                    }
164	                }
165	        }
166	    }
167	
168	    fun unsharePost(postId: String) {
169	        // Optimistic update
170	        _uiState.update { state ->
171	            state.copy(
172	                posts = state.posts.map { post ->
173	                    if (post.id == postId) {
174	                        post.copy(
175	                            viewerHasShared = false,
176	                            engagementStats = post.engagementStats.copy(
177	                                shares = maxOf(0, post.engagementStats.shares - 1)
178	                            )
179	                        )
180	                    } else post
181	                }
182	            )
183	        }
184	        viewModelScope.launch {
185	            repository.unsharePost(postId)
186	                .onFailure {
187	                    // Revert on failure
188	                    _uiState.update { state ->
189	                        state.copy(
190	                            posts = state.posts.map { post ->
191	                                if (post.id == postId) {
192	                                    post.copy(
193	                                        viewerHasShared = true,
194	                                        engagementStats = post.engagementStats.copy(
195	                                            shares = post.engagementStats.shares + 1
196	                                        )
197	                                    )
198	                                } else post
199	                            }
200	                        )
201	                    }
202	                }
203	        }
204	    }
205	
206	    fun toggleFavourite(postId: String) {
207	        toggleReaction(postId, "❤️")
208	    }
209	
210	    fun toggleReaction(postId: String, emoji: String) {
211	        val post = _uiState.value.posts.find {
212	            it.id == postId || it.sharedPost?.id == postId
213	        } ?: return
214	        val targetPost = post.sharedPost ?: post
215	        val existingGroup = targetPost.reactionGroups.find { it.emoji == emoji }
216	        val viewerHasReacted = existingGroup?.viewerHasReacted == true
217	
218	        // Optimistic update
219	        _uiState.update { state ->
220	            state.copy(
221	                posts = state.posts.map { p ->
222	                    val target = p.sharedPost ?: p
223	                    if (target.id == targetPost.id) {
224	                        val updatedGroups = updateReactionGroups(
225	                            target.reactionGroups, emoji, viewerHasReacted
226	                        )
227	                        val totalReactions = updatedGroups.sumOf { it.count }
228	                        val updatedTarget = target.copy(
229	                            reactionGroups = updatedGroups,
230	                            engagementStats = target.engagementStats.copy(
231	                                reactions = totalReactions
232	                            )
233	                        )
234	                        if (p.sharedPost != null) p.copy(sharedPost = updatedTarget)
235	                        else updatedTarget
236	                    } else p
237	                },
238	                reactionPickerPostId = null
239	            )
240	        }
241	
242	        viewModelScope.launch {
243	            val result = if (viewerHasReacted) {
244	                repository.removeReactionFromPost(targetPost.id, emoji)
245	            } else {
246	                repository.addReactionToPost(targetPost.id, emoji)
247	            }
248	
249	            result.onFailure {
250	                // Revert on failure
251	                _uiState.update { state ->
252	                    state.copy(
253	                        posts = state.posts.map { p ->
254	                            val target = p.sharedPost ?: p
255	                            if (target.id == targetPost.id) {
256	                                val revertedGroups = updateReactionGroups(
257	                                    target.reactionGroups, emoji, !viewerHasReacted
258	                                )
259	                                val totalReactions = revertedGroups.sumOf { it.count }
260	                                val revertedTarget = target.copy(
261	                                    reactionGroups = revertedGroups,
262	                                    engagementStats = target.engagementStats.copy(
263	                                        reactions = totalReactions
264	                                    )
265	                                )
266	                                if (p.sharedPost != null) p.copy(sharedPost = revertedTarget)
267	                                else revertedTarget
268	                            } else p
269	                        }
270	                    )
271	                }
272	            }
273	        }
274	    }
275	
276	    fun showReactionPicker(postId: String) {
277	        _uiState.update { it.copy(reactionPickerPostId = postId) }
278	    }
279	
280	    fun hideReactionPicker() {
281	        _uiState.update { it.copy(reactionPickerPostId = null) }
282	    }
283	
284	    private fun updateReactionGroups(
285	        groups: List<ReactionGroup>,
286	        emoji: String,
287	        wasReacted: Boolean
288	    ): List<ReactionGroup> {
289	        return if (wasReacted) {
290	            groups.map { group ->
291	                if (group.emoji == emoji) {
292	                    group.copy(count = maxOf(0, group.count - 1), viewerHasReacted = false)
293	                } else group
294	            }.filter { it.count > 0 || it.viewerHasReacted }
295	        } else {
296	            val existing = groups.find { it.emoji == emoji }
297	            if (existing != null) {
298	                groups.map { group ->
299	                    if (group.emoji == emoji) {
300	                        group.copy(count = group.count + 1, viewerHasReacted = true)
301	                    } else group
302	                }
303	            } else {
304	                groups + ReactionGroup(
305	                    emoji = emoji, customEmoji = null,
306	                    count = 1, reactors = emptyList(), viewerHasReacted = true
307	                )
308	            }
309	        }
310	    }
311	}
